ent(transparent 50%,var(--wp--custom--color--beige) 50%);background-size:auto 200%;border:0;border-radius:0;color:inherit;display:block;font-size:var(--wp--preset--font-size--small-text);font-weight:600;-webkit-text-decoration:underline!important;text-decoration:underline!important;text-underline-offset:.375rem;transition:background-position var(--wp--custom--duration-m) var(--wp--custom--easing-default);width:auto}.program-finder__filters-reset:hover{--btn-bg:transparent;background-position:0 100%;color:var(--wp--custom--color--charcoal)}.program-finder__filters-reset[disabled]{cursor:not-allowed;opacity:.4;pointer-events:none}.program-finder__filters-reset[target=_blank]{display:inline}.program-finder__filters-reset[target=_blank]:after{background-color:currentcolor;content:\a0";display:inline;flex:0 0 1.1em;height:1.1em;-webkit-mask-image:url(/wp-content/themes/hsph-theme/dist/blocks/program-finder/../svg/arrow-45.svg)
